const body = $input.first().json.body;

const transcript = body?.transcript?.trim();
if (!transcript) {
  return [{ json: { isValid: false } }];
}

return [{
  json: {
    isValid: true,
    transcript: transcript,
    date: body.date || new Date().toISOString().split('T')[0],
    source: body.source || 'unknown'
  }
}];

