parameters.jsCode:
const validated = $('Validate Transcript').item.json;
const jobsResponse = $input.first().json;

const jobs = (jobsResponse.organization?.jobs?.nodes || []).map(j => ({
  id: j.id,
  number: j.number,
  name: j.name,
  account: j.name.split(' - ')[0] || 'Unknown'
}));

const jobsList = jobs.map(j => `- #${j.number} ${j.name} (${j.account}) [ID: ${j.id}]`).join('\n');

const systemPrompt = `You are a construction job costing assistant. Extract structured data from voice transcripts.

ACTIVE JOBS:
${jobsList}

TRADE CATEGORIES (use these cost code IDs):
- Demo → 22Nm3uGRAMmJ (0200 Demolition)
- Framing → 22Nm3uGRAMmN (0600 Framing)
- Plumbing → 22Nm3uGRAMmT (1100 Plumbing)
- Electrical → 22Nm3uGRAMmS (1000 Electrical)
- Tile → 22Nm3uGRAMma (1800 Tiling)
- Drywall → 22Nm3uGRAMmW (1400 Drywall)
- Painting → 22Nm3uGRAMmf (2300 Painting)
- Finish Carpentry → 22Nm3uGRAMmb (1900 Cabinetry)
- Admin → 22Nm3uGRAMmH (0100 Planning)

OUTPUT JSON SCHEMA:
{
  "job_match": {
    "job_id": "string (from active jobs list)",
    "job_name": "string",
    "job_number": "string",
    "confidence": "high" | "medium" | "low"
  },
  "time_entries": [
    {
      "trade": "string (category name)",
      "cost_code_id": "string (from mappings above)",
      "hours": number,
      "description": "string (what was done)"
    }
  ],
  "materials": [
    {
      "item": "string",
      "quantity": number,
      "unit": "string",
      "notes": "string"
    }
  ],
  "conditions": [
    {
      "type": "issue" | "delay" | "change" | "note",
      "description": "string"
    }
  ],
  "daily_log_summary": "string (2-3 sentence summary for JT daily log)",
  "tomorrow_plan": "string (if mentioned)"
}

Rules:
- Match job by name/number mentioned in transcript
- If unsure which job, set confidence to "low"
- Sum up hours by trade category
- Extract any materials purchased or used
- Note any issues, delays, or changes
- Return ONLY valid JSON, no markdown`;

return [{
  json: {
    transcript: validated.transcript,
    date: validated.date,
    source: validated.source,
    systemPrompt: systemPrompt,
    activeJobs: jobs
  }
}];

const claudeResponse = $input.first().json;
const context = $('Prepare Claude Prompt').item.json;

let content = claudeResponse.content?.[0]?.text || '';

// Try to parse JSON from response
let parsed;
try {
  // Handle potential markdown code blocks
  const jsonMatch = content.match(/```json\s*([\s\S]*?)```/) || content.match(/```\s*([\s\S]*?)```/);
  const jsonStr = jsonMatch ? jsonMatch[1].trim() : content.trim();
  parsed = JSON.parse(jsonStr);
} catch (e) {
  throw new Error(`Failed to parse Claude response: ${e.message}`);
}

const totalHours = (parsed.time_entries || []).reduce((sum, e) => sum + (e.hours || 0), 0);

return [{
  json: {
    ...parsed,
    date: context.date,
    source: context.source,
    transcript: context.transcript,
    total_hours: totalHours,
    entries_count: (parsed.time_entries || []).length
  }
}];

